package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testToString() {
    LineItem item = new LineItem("apple", 3, 2500000L, "USD");
    String expected = "(item: apple, qty: 3, price: 2.50 USD)";
    assertEquals(expected, item.toString());
  }

  @Test
  void testToString_zeroQuantityAndPrice() {
    LineItem item = new LineItem("banana", 0, 0L, "EUR");
    String expected = "(item: banana, qty: 0, price: 0.00 EUR)";
    assertEquals(expected, item.toString());
  }

  @Test
  void testToString_nullNameAndCurrency() {
    LineItem item = new LineItem(null, 5, 123456789L, null);
    String expected = "(item: null, qty: 5, price: 123.46 null)";
    assertEquals(expected, item.toString());
  }
}
